import { drizzle } from "drizzle-orm/node-postgres";
import { Pool } from "pg";
import { charactersTable } from "./schema/characters.js";

const pool = new Pool({ connectionString: process.env.DATABASE_URL });
const db = drizzle(pool);

type Rarity = "D" | "C" | "B" | "A" | "S" | "SS" | "SSS" | "SSS+";
type Element = "Fire" | "Water" | "Earth" | "Wind" | "Lightning" | "Ice" | "Light" | "Dark" | "Chaos" | "Order" | "Space" | "Time";

function stats(rarity: Rarity, seed: number) {
  const r = (min: number, max: number, s: number) => Math.floor(min + ((s * 9301 + 49297) % 233280) / 233280 * (max - min));
  const ranges: Record<Rarity, { hp: [number, number]; atk: [number, number]; def: [number, number]; spd: [number, number]; crit: [number, number]; critDmg: [number, number] }> = {
    "D":    { hp: [500,800],    atk: [80,120],   def: [50,80],   spd: [60,100],  crit: [5,10],   critDmg: [130,150] },
    "C":    { hp: [800,1200],   atk: [120,180],  def: [80,120],  spd: [90,130],  crit: [8,12],   critDmg: [140,160] },
    "B":    { hp: [1200,1800],  atk: [180,260],  def: [120,180], spd: [120,160], crit: [10,15],  critDmg: [150,170] },
    "A":    { hp: [1800,2500],  atk: [260,380],  def: [180,260], spd: [150,200], crit: [12,18],  critDmg: [160,180] },
    "S":    { hp: [2500,3500],  atk: [380,520],  def: [260,380], spd: [190,250], crit: [15,20],  critDmg: [170,200] },
    "SS":   { hp: [3500,5000],  atk: [520,720],  def: [380,520], spd: [240,310], crit: [18,25],  critDmg: [190,220] },
    "SSS":  { hp: [5000,7000],  atk: [720,980],  def: [520,720], spd: [300,380], crit: [22,28],  critDmg: [210,250] },
    "SSS+": { hp: [7000,10000], atk: [980,1400], def: [720,980], spd: [370,450], crit: [28,35],  critDmg: [250,300] },
  };
  const g = ranges[rarity];
  return {
    baseHp: r(g.hp[0], g.hp[1], seed),
    baseAtk: r(g.atk[0], g.atk[1], seed + 1),
    baseDef: r(g.def[0], g.def[1], seed + 2),
    baseSpd: r(g.spd[0], g.spd[1], seed + 3),
    baseCrit: r(g.crit[0], g.crit[1], seed + 4) / 100,
    baseCritDmg: r(g.critDmg[0], g.critDmg[1], seed + 5) / 100,
  };
}

const SKILLS: Record<string, [string, string, string, string]> = {
  Fire:      ["Flame Strike", "Inferno Burst", "Blazing Fury", "Pyro Aura"],
  Water:     ["Aqua Slash", "Tidal Wave", "Water Prison", "Ocean's Embrace"],
  Earth:     ["Stone Crush", "Earthquake", "Iron Defense", "Terra Shield"],
  Wind:      ["Wind Blade", "Tornado Spin", "Air Assault", "Gale Force"],
  Lightning: ["Thunder Strike", "Lightning Bolt", "Static Charge", "Storm Surge"],
  Ice:       ["Ice Lance", "Blizzard", "Frozen Domain", "Frost Armor"],
  Light:     ["Holy Beam", "Divine Judgment", "Sacred Shield", "Radiant Aura"],
  Dark:      ["Shadow Slash", "Dark Void", "Soul Drain", "Eclipse"],
  Chaos:     ["Chaos Burst", "Entropy Wave", "Void Rift", "Chaotic Form"],
  Order:     ["Order Strike", "Law's Judgment", "Rule Enforcement", "Balance"],
  Space:     ["Space Rend", "Dimension Gate", "Gravity Crush", "Void Step"],
  Time:      ["Time Slash", "Temporal Freeze", "Rewind", "Time Lock"],
};

function skillSet(el: Element) {
  return SKILLS[el] ?? SKILLS.Fire;
}

